                    },
                    {
                        "item": "viz_threat_beacon",
                        "type": "block",
                        "position": { "x": 24, "y": 98, "w": 454, "h": 409 }
                    },
                    {
                        "item": "viz_attack_heatmap",
                        "type": "block",
                        "position": { "x": 502, "y": 98, "w": 824, "h": 409 }
                    },
                    {
                        "item": "viz_host_shield_grid",
                        "type": "block",
                        "position": { "x": 1350, "y": 98, "w": 546, "h": 409 }
                    },
                    {
                        "item": "viz_threat_feed",
