                    },
                    {
                        "item": "viz_defense_ranking",
                        "type": "block",
                        "position": { "x": 1350, "y": 551, "w": 546, "h": 505 }
                    }
                ]
            }
        }
    },
    "title": "NordShield Threat Operations Center",
    "description": "SOC wall dashboard for NordShield Cyber Defense"
}
